<?phpdefine("RelativePath", ".");include(RelativePath . "/Common.php");set_time_limit(0);$file_type = "vnd.ms-excel";$name = CCGetSession('nameXls') . "_" . date('d_m_Y');$file_ending = "xls";$filename = $name . "." . $file_ending;header("Content-Type: application/$file_type");header("Content-Disposition: attachment; filename=".$filename);header("Pragma: no-cache");header("Expires: 0");function encabezado($c){	while (list ($clave, $val) = each ($c)){		echo $val . "\t";	}	print("\n");}$SQL = CCGetSession('qryXls');$col = CCGetParam('columnas');$all = CCGetSession('colXls');while (list ($clave, $val) = each ($col)) {	if(array_key_exists($val,$all)){		$campos[$val] = $all[$val];	} }$SQL = str_replace("{SQL_Where}","",$SQL);$SQL = str_replace("{SQL_OrderBy}","",$SQL);//echo $SQL;exit;$db = new clsDBtdf_nuevo();$db2 = new clsDBtdf_nuevo();$db3 = new clsDBtdf_nuevo();encabezado($campos);$sep = "\t";$db->query($SQL);$fila=1;$columna = 1;while($db->next_record()){	//echo $db->f('reg_n_registro') . "<br>";	$schema_insert = "";		while (list($k,$v) = each($campos)){		$coma = "";		if(!$db->f($k)){//si es vacio salta a la otra celda			if($fila > 0 && $columna == 21){				$usos = "";				$SQL="SELECT tipo_uso_suelo_id FROM parcelas_usos_suelo WHERE parcela_id = ".$db->f('parcela_id');				$db2->query($SQL);				while($db2->next_record()){					$usos.=$coma.CCDLookUp("tipo_uso_suelo_descrip","tipos_usos_suelo","tipo_uso_suelo_id=".$db2->f('tipo_uso_suelo_id'),$db3);					$coma = ",";				}				$schema_insert .= $usos.$sep;			}elseif($fila > 0 && $columna == 27){//columna restricciones				$restricc = "";				$SQL="SELECT tipo_restricc_parcela_id FROM parcelas_tipos_restricc WHERE parcela_id = ".$db->f('parcela_id');				$db2->query($SQL);				while($db2->next_record()){					$restricc.=$coma.CCDLookUp("tipo_restricc_parcela_desc","tipos_restricc_parcela","tipo_restricc_parcela_id=".$db2->f('tipo_restricc_parcela_id'),$db3);					$coma = ",";				}				$schema_insert .= $restricc.$sep;			}else{				$schema_insert .= "".$sep;			}		}else{//sino es vacio			if(is_numeric($db->f($k))){//si es un numero				$str = str_replace('.',',',$db->f($k));				$coma = "";								if($fila > 0 && $columna == 21){					$usos = "";					$SQL="SELECT tipo_uso_suelo_id FROM parcelas_usos_suelo WHERE parcela_id = ".$db->f('parcela_id');					$db2->query($SQL);					while($db2->next_record()){						$usos.=$coma.CCDLookUp("tipo_uso_suelo_descrip","tipos_usos_suelo","tipo_uso_suelo_id=".$db2->f('tipo_uso_suelo_id'),$db3);						$coma = ",";					}					$str = $usos;				}elseif($fila > 0 && $columna == 27){//columna restricciones					$restricc = "";					$SQL="SELECT tipo_restricc_parcela_id FROM parcelas_tipos_restricc WHERE parcela_id = ".$db->f('parcela_id');					$db2->query($SQL);					while($db2->next_record()){						$restricc.=$coma.CCDLookUp("tipo_restricc_parcela_desc","tipos_restricc_parcela","tipo_restricc_parcela_id=".$db2->f('tipo_restricc_parcela_id'),$db3);						$coma = ",";					}					$str = $restricc;				}			}else{//sino es un numero					$str = $db->f($k);				$coma = "";								if($fila > 0 && $columna == 21){					$usos = "";					$SQL="SELECT tipo_uso_suelo_id FROM parcelas_usos_suelo WHERE parcela_id = ".$db->f('parcela_id');					$db2->query($SQL);					while($db2->next_record()){						$usos.=$coma.CCDLookUp("tipo_uso_suelo_descrip","tipos_usos_suelo","tipo_uso_suelo_id=".$db2->f('tipo_uso_suelo_id'),$db3);						$coma = ",";					}					$str = $usos;				}elseif($fila > 0 && $columna == 27){//columna restricciones					$restricc = "";					$SQL="SELECT tipo_restricc_parcela_id FROM parcelas_tipos_restricc WHERE parcela_id = ".$db->f('parcela_id');					$db2->query($SQL);					while($db2->next_record()){						$restricc.=$coma.CCDLookUp("tipo_restricc_parcela_desc","tipos_restricc_parcela","tipo_restricc_parcela_id=".$db2->f('tipo_restricc_parcela_id'),$db3);						$coma = ",";					}					$str = $restricc;				}			}			$schema_insert .= $str.$sep;		}		$columna++;	}	$schema_insert = preg_replace("/\r\n|\n\r|\n|\r/", " ", $schema_insert);	$schema_insert .= "\t";	$schema_insert = trim($schema_insert);	echo($schema_insert);	echo "\n";	reset($campos);	$fila++;	$ultimo=$columna;	$columna=1;}$db->close();$db2->close();$db3->close();?>